const TIMELINE_TEXT_BY_LOCALE = Object.freeze({
  es: Object.freeze(
    Object.fromEntries(
      TIMELINE_EVENT_BANK_RAW.map((event) => [
        event.id,
        { title: event.title.es, summary: event.summary.es },
      ])
    )
  ),
  en: Object.freeze(
    Object.fromEntries(
      TIMELINE_EVENT_BANK_RAW.map((event) => [
        event.id,
        { title: event.title.en, summary: event.summary.en },
      ])
    )
  ),
});

const normalizeLocale = (locale) =>
  String(locale || "").toLowerCase().startsWith("es") ? "es" : "en";

export const TIMELINE_EVENT_BANK = Object.freeze(
  TIMELINE_EVENT_BANK_RAW.map(({ id, year }) => ({ id, year }))
);

export const loadTimelineEventLocale = async (locale) => {
  const localeKey = normalizeLocale(locale);
  return TIMELINE_TEXT_BY_LOCALE[localeKey] || TIMELINE_TEXT_BY_LOCALE.en;
};

export const loadTimelineEventBank = async (locale) => {
  const localeText = await loadTimelineEventLocale(locale);
  return TIMELINE_EVENT_BANK.map((event) => ({
    ...event,
    title: localeText[event.id]?.title ?? "",
    summary: localeText[event.id]?.summary ?? "",
  }));
};

export const getTimelineEventText = (event, locale, field = "title") => {
  const localeKey = normalizeLocale(locale);
  const localeText = TIMELINE_TEXT_BY_LOCALE[localeKey] || {};
  const text = localeText[event?.id]?.[field];
  return text ?? event?.id ?? "";
};
